functions.body:
local target_header="${1:-}"
local notes_file="${BASH4LLM_EXTRAS_DIR:-}/docs/core-notes.sh"
if [ ! -f "$notes_file" ] || [ ! -r "$notes_file" ]; then
  return 1
fi
awk -v header="$target_header" '
  index($0, header) { flag=1; next }
  /^[[:space:]]*$/ { if (flag) { flag=0; exit } }
  flag { print }
' "$notes_file" 2>/dev/null

case "${1:-}" in
  1|true|TRUE|True|yes|YES|Yes) return 0 ;;
  *) return 1 ;;
esac
